## Desktop Mesh Design

### Approach Name: **Relay-Routed Peer Queries**

### Philosophy

Every desktop instance is already a q:\* protocol server with relay connectivity. Instead of building peer-to-peer connections, we make each desktop instance also act as a q:\* protocol *client* for other desktops, routing queries through the existing cloud relay. The smallest step that works: one desktop subscribes to another desktop's resources through the same relay both already connect to.

### How the Current System Works (Summary)

The current architecture has three participants:

1. **Desktop backend** -- connects *outbound* to the cloud relay as a "server" via `relay.service.ts`. Registers with `serverId` + `relayToken`. Handles `client_connected`/`data`/`client_disconnected` frames.

2. **Cloud relay** (Cloudflare Durable Object) -- routes frames between servers and clients. A client connects with a `serverId` target and a `deviceToken`.

3. **Web client** (or mobile) -- connects to the relay targeting a specific `serverId`, authenticates with a `deviceToken`, sends `q:*` frames. Gets back `q:snapshot`/`q:delta`/`q:invalidate`.

The key insight: **the relay already supports bidirectional q:\* protocol**. A desktop backend *could* act as a "client" of another desktop backend, if it connected to the relay targeting that other server's `serverId`.

### Architecture for Desktop Mesh

```
Desktop A (local)                    Cloud Relay                    Desktop B (remote GPU)
┌─────────────────┐                 ┌──────────┐                 ┌─────────────────┐
│ Backend          │═══tunnel═══════│          │═══tunnel════════│ Backend          │
│ (server role)    │                │  Relay   │                │ (server role)    │
│                  │                │          │                │                  │
│ MeshClient ──────┼──client conn──→│          │───forwarded────→│ handles q:*      │
│ (client role)    │                │          │                │ from A as if     │
│                  │                └──────────┘                │ web client       │
│ MeshRegistry     │                                            │                  │
│ (tracks peers)   │                                            │ MeshClient ──────┼──→ ...
└─────────────────┘                                            └─────────────────┘
```

Each desktop maintains:
- Its **existing server tunnel** (unchanged)
- Zero or more **mesh client connections** to other desktops' serverIds through the relay

### Implementation Sketch (Critical Path)

Here is the real TypeScript for the core new module:

**File: `backend/src/services/mesh.service.ts`** (new)

```typescript
// backend/src/services/mesh.service.ts
// Desktop Mesh — connects to peer desktop instances through the cloud relay.
// Each peer connection acts as a q:* protocol client, subscribing to the
// remote desktop's resources and forwarding data to the local frontend.

import { WebSocket } from "ws";
import { match } from "ts-pattern";
import { getSetting } from "./settings.service";
import { getRelayCredentials } from "./remote-auth.service";
import { DEFAULT_RELAY_URL } from "../lib/network";
import { broadcast } from "./ws.service";
import type { QServerFrame } from "../../../shared/types/query-protocol";

// ---- Types ----

export interface MeshPeer {
  /** The remote desktop's relay server ID. */
  serverId: string;
  /** Device token for authenticating with the remote desktop. */
  deviceToken: string;
  /** Human-readable name for the remote desktop. */
  name: string;
}

interface PeerConnection {
  peer: MeshPeer;
  ws: WebSocket | null;
  connected: boolean;
  authenticated: boolean;
  reconnectTimer: ReturnType<typeof setTimeout> | null;
  reconnectAttempt: number;
  /** Active subscription IDs on this peer, keyed by local sub ID. */
  subscriptions: Map<string, { resource: string; params?: Record<string, unknown> }>;
}

// ---- State ----

const peers = new Map<string, PeerConnection>();

const BACKOFF_BASE_MS = 1_000;
const BACKOFF_MAX_MS = 30_000;

// ---- Public API ----

/** Add a peer and connect to it through the relay. */
export function addPeer(peer: MeshPeer): void {
  if (peers.has(peer.serverId)) {
    console.log(`[Mesh] Peer ${peer.serverId} already registered`);
    return;
  }

  const conn: PeerConnection = {
    peer,
    ws: null,
    connected: false,
    authenticated: false,
    reconnectTimer: null,
    reconnectAttempt: 0,
    subscriptions: new Map(),
  };

  peers.set(peer.serverId, conn);
  openPeerConnection(conn);
}

/** Remove a peer and disconnect. */
export function removePeer(serverId: string): void {
  const conn = peers.get(serverId);
  if (!conn) return;

  if (conn.reconnectTimer) clearTimeout(conn.reconnectTimer);
  if (conn.ws) conn.ws.close(1000, "Peer removed");
  peers.delete(serverId);

  // Notify frontend that this peer's data is gone
  broadcastMeshEvent({
    type: "mesh:peer_disconnected",
    serverId,
  });
}

/** List all registered peers with connection status. */
export function listPeers(): Array<{
  serverId: string;
  name: string;
  connected: boolean;
  authenticated: boolean;
}> {
  return Array.from(peers.values()).map((c) => ({
    serverId: c.peer.serverId,
    name: c.peer.name,
    connected: c.connected,
    authenticated: c.authenticated,
  }));
}

/** Subscribe to a resource on a specific peer. Returns unsubscribe function. */
export function subscribeToPeer(
  serverId: string,
  resource: string,
  params?: Record<string, unknown>,
): { subId: string; unsubscribe: () => void } | null {
  const conn = peers.get(serverId);
  if (!conn) return null;

  const subId = `mesh_${serverId}_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`;

  conn.subscriptions.set(subId, { resource, params });

  // If already authenticated, send subscribe immediately
  if (conn.authenticated && conn.ws?.readyState === WebSocket.OPEN) {
    sendToPeer(conn, {
      type: "q:subscribe",
      id: subId,
      resource,
      ...(params ? { params } : {}),
    });
  }

  return {
    subId,
    unsubscribe: () => {
      conn.subscriptions.delete(subId);
      if (conn.authenticated && conn.ws?.readyState === WebSocket.OPEN) {
        sendToPeer(conn, { type: "q:unsubscribe", id: subId });
      }
    },
  };
}

// ---- Peer Connection Lifecycle ----

function openPeerConnection(conn: PeerConnection): void {
  const relayUrl =
    (getSetting("relay_url") as string | null) ?? DEFAULT_RELAY_URL;

  // Connect as a CLIENT to the relay, targeting the peer's serverId
  const wsUrl = `${relayUrl}/api/servers/${conn.peer.serverId}/ws`;

  try {
    conn.ws = new WebSocket(wsUrl);
  } catch (err) {
    console.error(`[Mesh] Failed to connect to peer ${conn.peer.serverId}:`, err);
    schedulePeerReconnect(conn);
    return;
  }

  conn.ws.on("open", () => {
    console.log(`[Mesh] Connected to relay for peer ${conn.peer.serverId}, authenticating...`);
    conn.connected = true;
    conn.reconnectAttempt = 0;

    // Authenticate with the remote desktop's device token
    sendToPeer(conn, {
      type: "authenticate",
      token: conn.peer.deviceToken,
    });
  });

  conn.ws.on("message", (raw: Buffer | string) => {
    try {
      const msg = JSON.parse(typeof raw === "string" ? raw : raw.toString());
      handlePeerMessage(conn, msg);
    } catch {
      // Ignore malformed
    }
  });

  conn.ws.on("close", () => {
    console.log(`[Mesh] Peer ${conn.peer.serverId} disconnected`);
    conn.connected = false;
    conn.authenticated = false;
    conn.ws = null;

    // Only reconnect if peer is still registered
    if (peers.has(conn.peer.serverId)) {
      schedulePeerReconnect(conn);
      broadcastMeshEvent({
        type: "mesh:peer_disconnected",
        serverId: conn.peer.serverId,
      });
    }
  });

  conn.ws.on("error", (err) => {
    console.error(`[Mesh] Peer ${conn.peer.serverId} error:`, err.message);
  });
}

function handlePeerMessage(conn: PeerConnection, msg: Record<string, unknown>): void {
  const type = typeof msg.type === "string" ? msg.type : "";

  match(type)
    .with("authenticated", () => {
      console.log(`[Mesh] Authenticated with peer ${conn.peer.serverId}`);
      conn.authenticated = true;

      // Re-subscribe all active subscriptions
      for (const [subId, sub] of conn.subscriptions) {
        sendToPeer(conn, {
          type: "q:subscribe",
          id: subId,
          resource: sub.resource,
          ...(sub.params ? { params: sub.params } : {}),
        });
      }

      broadcastMeshEvent({
        type: "mesh:peer_connected",
        serverId: conn.peer.serverId,
        name: conn.peer.name,
      });
    })
    .with("auth_failed", () => {
      console.error(`[Mesh] Auth failed for peer ${conn.peer.serverId}: ${msg.message}`);
      conn.ws?.close(4001, "Auth failed");
    })
    .with("server_offline", () => {
      console.log(`[Mesh] Peer ${conn.peer.serverId} is offline`);
      broadcastMeshEvent({
        type: "mesh:peer_offline",
        serverId: conn.peer.serverId,
      });
    })
    .with("connected", () => {
      // The remote desktop's WS handler sends "connected" after auth.
      // This is the direct WS path — relay uses "authenticated" instead.
      // Handle both for robustness.
      conn.authenticated = true;

      for (const [subId, sub] of conn.subscriptions) {
        sendToPeer(conn, {
          type: "q:subscribe",
          id: subId,
          resource: sub.resource,
          ...(sub.params ? { params: sub.params } : {}),
        });
      }
    })
    .with("ping", () => {
      sendToPeer(conn, { type: "pong" });
    })
    .otherwise(() => {
      // Forward q:* frames to local frontend, tagged with peer origin
      if (type.startsWith("q:")) {
        forwardPeerFrame(conn, msg as Record<string, unknown>);
      }
    });
}

/**
 * Forward a q:* frame from a peer to all local frontend connections.
 * Tags the frame with `peerId` so the frontend can distinguish
 * local vs remote data.
 */
function forwardPeerFrame(conn: PeerConnection, frame: Record<string, unknown>): void {
  broadcast(
    JSON.stringify({
      ...frame,
      peerId: conn.peer.serverId,
      peerName: conn.peer.name,
    })
  );
}

function sendToPeer(conn: PeerConnection, frame: Record<string, unknown>): void {
  if (conn.ws?.readyState === WebSocket.OPEN) {
    try {
      conn.ws.send(JSON.stringify(frame));
    } catch {
      // Will be handled by close/error
    }
  }
}

function schedulePeerReconnect(conn: PeerConnection): void {
  if (conn.reconnectTimer) return;

  const delay = Math.min(
    BACKOFF_BASE_MS * 2 ** conn.reconnectAttempt,
    BACKOFF_MAX_MS
  );
  conn.reconnectAttempt++;

  console.log(
    `[Mesh] Reconnecting to peer ${conn.peer.serverId} in ${delay}ms (attempt ${conn.reconnectAttempt})`
  );

  conn.reconnectTimer = setTimeout(() => {
    conn.reconnectTimer = null;
    openPeerConnection(conn);
  }, delay);
}

function broadcastMeshEvent(event: Record<string, unknown>): void {
  broadcast(JSON.stringify(event));
}

/** Disconnect all peers (for shutdown). */
export function disconnectAllPeers(): void {
  for (const [, conn] of peers) {
    if (conn.reconnectTimer) clearTimeout(conn.reconnectTimer);
    if (conn.ws) conn.ws.close(1000, "Shutting down");
  }
  peers.clear();
}
```

