// shared/types/mesh.ts
// Types for the Desktop Mesh feature.

/** Peer desktop instance that this desktop can connect to. */
export interface MeshPeerConfig {
  /** Remote desktop's relay server ID (8-char hex). */
  serverId: string;
  /** Device token obtained by pairing with the remote desktop. */
  deviceToken: string;
  /** Human-readable name (e.g., "GPU Cluster A"). */
  name: string;
}

/** Status of a peer connection as seen by the local desktop. */
export interface MeshPeerStatus {
  serverId: string;
  name: string;
  connected: boolean;
  authenticated: boolean;
}

/** Mesh lifecycle events forwarded to the frontend via WS broadcast. */
export type MeshEvent =
  | { type: "mesh:peer_connected"; serverId: string; name: string }
  | { type: "mesh:peer_disconnected"; serverId: string }
  | { type: "mesh:peer_offline"; serverId: string };
