  return c.json({ peers: listPeers() });
});

app.post('/api/mesh/peers', async (c) => {
  const { serverId, deviceToken, name } = await c.req.json();
  if (!serverId || !deviceToken || !name) {
    return c.json({ error: "serverId, deviceToken, and name are required" }, 400);
  }
  addPeer({ serverId, deviceToken, name });
  return c.json({ success: true });
});

app.delete('/api/mesh/peers/:serverId', (c) => {
  removePeer(c.req.param('serverId'));
  return c.json({ success: true });
});
