  conn.ws.on("message", (raw: Buffer | string) => {
    try {
      const msg = JSON.parse(typeof raw === "string" ? raw : raw.toString());
      handlePeerMessage(conn, msg);
    } catch {
      // Ignore malformed
    }
  });

  conn.ws.on("close", () => {
    console.log(`[Mesh] Peer ${conn.peer.serverId} disconnected`);
    conn.connected = false;
    conn.authenticated = false;
    conn.ws = null;

    // Only reconnect if peer is still registered
    if (peers.has(conn.peer.serverId)) {
      schedulePeerReconnect(conn);
      broadcastMeshEvent({
        type: "mesh:peer_disconnected",
        serverId: conn.peer.serverId,
      });
    }
  });

  conn.ws.on("error", (err) => {
    console.error(`[Mesh] Peer ${conn.peer.serverId} error:`, err.message);
  });
}

function handlePeerMessage(conn: PeerConnection, msg: Record<string, unknown>): void {
  const type = typeof msg.type === "string" ? msg.type : "";

  match(type)
    .with("authenticated", () => {
      console.log(`[Mesh] Authenticated with peer ${conn.peer.serverId}`);
      conn.authenticated = true;

      // Re-subscribe all active subscriptions
      for (const [subId, sub] of conn.subscriptions) {
        sendToPeer(conn, {
          type: "q:subscribe",
          id: subId,
          resource: sub.resource,
          ...(sub.params ? { params: sub.params } : {}),
        });
      }

      broadcastMeshEvent({
        type: "mesh:peer_connected",
        serverId: conn.peer.serverId,
        name: conn.peer.name,
      });
    })
    .with("auth_failed", () => {
      console.error(`[Mesh] Auth failed for peer ${conn.peer.serverId}: ${msg.message}`);
      conn.ws?.close(4001, "Auth failed");
    })
    .with("server_offline", () => {
      console.log(`[Mesh] Peer ${conn.peer.serverId} is offline`);
      broadcastMeshEvent({
        type: "mesh:peer_offline",
        serverId: conn.peer.serverId,
      });
    })
    .with("connected", () => {
      // The remote desktop's WS handler sends "connected" after auth.
      // This is the direct WS path — relay uses "authenticated" instead.
      // Handle both for robustness.
      conn.authenticated = true;

      for (const [subId, sub] of conn.subscriptions) {
        sendToPeer(conn, {
          type: "q:subscribe",
          id: subId,
          resource: sub.resource,
          ...(sub.params ? { params: sub.params } : {}),
        });
      }
    })
    .with("ping", () => {
      sendToPeer(conn, { type: "pong" });
    })
    .otherwise(() => {
      // Forward q:* frames to local frontend, tagged with peer origin
      if (type.startsWith("q:")) {
        forwardPeerFrame(conn, msg as Record<string, unknown>);
      }
    });
}

/**
 * Forward a q:* frame from a peer to all local frontend connections.
 * Tags the frame with `peerId` so the frontend can distinguish
 * local vs remote data.
 */
function forwardPeerFrame(conn: PeerConnection, frame: Record<string, unknown>): void {
  broadcast(
    JSON.stringify({
      ...frame,
      peerId: conn.peer.serverId,
      peerName: conn.peer.name,
    })
  );
}

function sendToPeer(conn: PeerConnection, frame: Record<string, unknown>): void {
  if (conn.ws?.readyState === WebSocket.OPEN) {
    try {
      conn.ws.send(JSON.stringify(frame));
    } catch {
      // Will be handled by close/error
    }
  }
}

function schedulePeerReconnect(conn: PeerConnection): void {
  if (conn.reconnectTimer) return;

  const delay = Math.min(
    BACKOFF_BASE_MS * 2 ** conn.reconnectAttempt,
    BACKOFF_MAX_MS
  );
  conn.reconnectAttempt++;

  console.log(
    `[Mesh] Reconnecting to peer ${conn.peer.serverId} in ${delay}ms (attempt ${conn.reconnectAttempt})`
  );

  conn.reconnectTimer = setTimeout(() => {
    conn.reconnectTimer = null;
    openPeerConnection(conn);
  }, delay);
}

function broadcastMeshEvent(event: Record<string, unknown>): void {
  broadcast(JSON.stringify(event));
}

/** Disconnect all peers (for shutdown). */
export function disconnectAllPeers(): void {
  for (const [, conn] of peers) {
    if (conn.reconnectTimer) clearTimeout(conn.reconnectTimer);
    if (conn.ws) conn.ws.close(1000, "Shutting down");
  }
  peers.clear();
}
