// ---- New: Peer-to-Peer Frames ----

/** Server → Relay: forward a q:* frame to another server */
// Added to ServerFrame union:
| { type: "peer_forward"; targetServerId: string; payload: string }

/** Relay → Server: a q:* frame arriving from another server */
// Added to RelayFrame union:
| { type: "peer_data"; sourceServerId: string; sourceName: string; payload: string }

/** Relay → Server: the target server is not connected */
| { type: "peer_unreachable"; targetServerId: string }

/** Server → Relay: request the list of currently connected servers */
| { type: "peer_discover" }

/** Relay → Server: list of connected servers (response to peer_discover) */
| { type: "peer_list"; servers: Array<{ serverId: string; serverName: string }> }
