Also important: when Desktop A receives a `peer_data` frame that contains a q:\* *request* or *subscribe* (i.e., another desktop is querying *our* data), we need to route it to our local query engine. This is the **server side** of the mesh -- Desktop A already knows how to answer q:\* frames through `handleFrame` in `query-engine.ts`. We just need a virtual connection for the peer:

```typescript
// In handleRelayFrame, for peer_data frames where the inner payload is a q:request or q:subscribe:

.with({ type: "peer_data" }, (f) => {
  const inner = JSON.parse(f.payload);
  const innerType = typeof inner.type === "string" ? inner.type : "";

  if (innerType.startsWith("q:") && isClientFrame(innerType)) {
    // Another desktop is querying OUR data. Create/reuse a virtual connection
    // for this peer and route through our local query engine.
    const connId = ensurePeerServerConnection(f.sourceServerId, f.sourceName);
    handleProtocolMessage(connId, inner);
  } else {
    // This is a response to OUR outbound subscription.
    handlePeerFrame(f.sourceServerId, f.payload);
  }
})
```

Where `ensurePeerServerConnection` creates a virtual `WsSendable` that routes responses back through the relay:

```typescript
// Virtual connections for peers querying OUR data (server role)
const peerServerConns = new Map<string, string>(); // peerId → connectionId

function ensurePeerServerConnection(peerId: string, peerName: string): string {
  const existing = peerServerConns.get(peerId);
  if (existing && getConnection(existing)) return existing;

  const virtualWs: WsSendable = {
    send(data: string | ArrayBuffer) {
      const payload = typeof data === "string" ? data : new TextDecoder().decode(data as ArrayBuffer);
      sendToRelay({ type: "peer_forward", targetServerId: peerId, payload });
    },
    close() { /* no-op */ },
  };

  const connId = addConnection(virtualWs, `peer:${peerId}`, true);
  peerServerConns.set(peerId, connId);
  return connId;
}

function isClientFrame(type: string): boolean {
  return type === "q:request" || type === "q:subscribe" || type === "q:unsubscribe" || type === "q:mutate";
}
