#### 3. WS Peer Proxy in `app.ts`

The frontend connects to `/ws/peer/:peerId` on its local backend. The backend proxies `q:*` frames to/from the peer via `mesh.service.ts`.

```typescript
// Addition to app.ts — peer WS proxy route
// Mount BEFORE the main /ws route

app.get('/ws/peer/:peerId', upgradeWebSocket((c) => {
  const peerId = c.req.param('peerId');
  const ip = getClientIp(c);

  // Only localhost can use peer proxy
  if (!isLocalhost(ip)) {
    return {
      onOpen(_evt, ws) {
        ws.send(JSON.stringify({ type: 'error', message: 'Localhost only' }));
        ws.close(4003, 'Forbidden');
      },
    };
  }

  return {
    onOpen(_evt, ws) {
      if (!isPeerConnected(peerId)) {
        ws.send(JSON.stringify({ type: 'error', message: 'Peer not connected' }));
        ws.close(4004, 'Peer offline');
        return;
      }

      // Register handler: peer → local WS client
      setPeerMessageHandler(peerId, (payload) => {
        try {
          ws.send(payload);
        } catch {
          // Client disconnected
        }
      });

      ws.send(JSON.stringify({ type: 'connected', peerId }));
    },

    onMessage(evt, _ws) {
      const raw = typeof evt.data === 'string' ? evt.data : String(evt.data);
      // Forward: local WS client → peer
      sendToPeer(peerId, raw);
    },

    onClose() {
      setPeerMessageHandler(peerId, null);
    },
  };
}));
```

#### 4. Frontend `PeerQueryClient` -- Per-Peer Protocol Client

```typescript
// src/platform/ws/peer-query-client.ts
// Per-peer query protocol client. Same protocol as query-protocol-client.ts
// but connects to /ws/peer/:peerId instead of /ws.

import { match } from "ts-pattern";
import { getBackendPort } from "@/shared/config/api.config";
import type { QueryResource } from "@shared/types/query-protocol";

type SnapshotCallback = (data: unknown) => void;
type DeltaCallback = (upserted?: unknown[], removed?: string[], cursor?: number) => void;
type StatusCallback = (status: "connected" | "disconnected" | "error") => void;

interface PeerSubscription {
  id: string;
  resource: QueryResource;
  params?: Record<string, unknown>;
  onSnapshot: SnapshotCallback;
  onDelta?: DeltaCallback;
}

export class PeerQueryClient {
  private peerId: string;
  private ws: WebSocket | null = null;
  private connected = false;
  private subscriptions = new Map<string, PeerSubscription>();
  private subCounter = 0;
  private statusListeners = new Set<StatusCallback>();
  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
  private reconnectAttempt = 0;

  constructor(peerId: string) {
    this.peerId = peerId;
  }

  async connect(): Promise<void> {
    if (this.connected) return;

    const port = await getBackendPort();
    const url = `ws://localhost:${port}/ws/peer/${this.peerId}`;
    this.ws = new WebSocket(url);

    return new Promise<void>((resolve, reject) => {
      this.ws!.onopen = () => {
        // Wait for "connected" frame
      };

      this.ws!.onmessage = (evt) => {
        let msg: Record<string, unknown>;
        try {
          msg = JSON.parse(evt.data as string);
        } catch {
          return;
        }

        const type = typeof msg.type === "string" ? msg.type : "";

        match(type)
          .with("connected", () => {
            this.connected = true;
            this.reconnectAttempt = 0;
            this.resubscribeAll();
            this.notifyStatus("connected");
            resolve();
          })
          .with("q:snapshot", () => {
            const sub = this.subscriptions.get(msg.id as string);
            sub?.onSnapshot(msg.data);
          })
          .with("q:delta", () => {
            const sub = this.subscriptions.get(msg.id as string);
            sub?.onDelta?.(
              msg.upserted as unknown[] | undefined,
              msg.removed as string[] | undefined,
              msg.cursor as number | undefined
            );
          })
          .with("q:error", () => {
            console.warn(`[Peer:${this.peerId}] Query error:`, msg.message);
          })
          .with("error", () => {
            this.notifyStatus("error");
            reject(new Error(msg.message as string));
          })
          .otherwise(() => { /* ignore */ });
      };

      this.ws!.onclose = () => {
        this.connected = false;
        this.ws = null;
        this.notifyStatus("disconnected");
        this.scheduleReconnect();
      };

      this.ws!.onerror = () => {
        // Cleanup in onclose
      };
    });
  }

  subscribe(
    resource: QueryResource,
    params: Record<string, unknown> | undefined,
    onSnapshot: SnapshotCallback,
    onDelta?: DeltaCallback
  ): () => void {
    const id = `peer_sub_${++this.subCounter}`;
    const sub: PeerSubscription = { id, resource, params, onSnapshot, onDelta };
    this.subscriptions.set(id, sub);

    if (this.connected && this.ws) {
      this.sendFrame({
        type: "q:subscribe",
        id,
        resource,
        ...(params ? { params } : {}),
      });
    }

    return () => {
      this.subscriptions.delete(id);
      if (this.connected && this.ws) {
        this.sendFrame({ type: "q:unsubscribe", id });
      }
    };
  }

  onStatus(callback: StatusCallback): () => void {
    this.statusListeners.add(callback);
    return () => this.statusListeners.delete(callback);
  }

  disconnect(): void {
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }
    if (this.ws) {
      this.ws.close(1000, "Client disconnect");
      this.ws = null;
    }
    this.connected = false;
    this.subscriptions.clear();
  }

  private sendFrame(frame: Record<string, unknown>): void {
    if (this.ws && this.ws.readyState === WebSocket.OPEN) {
      try {
        this.ws.send(JSON.stringify(frame));
      } catch { /* closed */ }
    }
  }

  private resubscribeAll(): void {
    for (const sub of this.subscriptions.values()) {
      this.sendFrame({
        type: "q:subscribe",
        id: sub.id,
        resource: sub.resource,
        ...(sub.params ? { params: sub.params } : {}),
      });
    }
  }

  private notifyStatus(status: "connected" | "disconnected" | "error"): void {
    for (const cb of this.statusListeners) {
      try { cb(status); } catch { /* ignore */ }
    }
  }

  private scheduleReconnect(): void {
    if (this.reconnectTimer || this.subscriptions.size === 0) return;

    const delay = Math.min(500 * 2 ** this.reconnectAttempt, 8000);
    this.reconnectAttempt++;

    this.reconnectTimer = setTimeout(() => {
      this.reconnectTimer = null;
      this.connect().catch(() => { /* onclose will retry */ });
    }, delay);
  }
}
```

#### 5. Frontend Hook: `usePeerSubscription.ts`

```typescript
// src/shared/hooks/usePeerSubscription.ts
// Identical to useQuerySubscription but for a specific peer desktop.

import { useEffect, useMemo, useRef } from "react";
import { useQueryClient, type QueryKey } from "@tanstack/react-query";
import type { QueryResource } from "@shared/types/query-protocol";
import type { PeerQueryClient } from "@/platform/ws/peer-query-client";

interface UsePeerSubscriptionOptions {
  queryKey: QueryKey;
  params?: Record<string, unknown>;
  enabled?: boolean;
}

export function usePeerSubscription(
  client: PeerQueryClient | null,
  resource: QueryResource,
  options: UsePeerSubscriptionOptions
): void {
  const { queryKey, params, enabled = true } = options;
  const queryClient = useQueryClient();

  const stableParamsKey = useMemo(
    () => (params ? JSON.stringify(params) : ""),
    [params]
  );

  const queryClientRef = useRef(queryClient);
  queryClientRef.current = queryClient;

  const queryKeyRef = useRef(queryKey);
  queryKeyRef.current = queryKey;

  useEffect(() => {
    if (!enabled || !client) return;

    const unsubscribe = client.subscribe(
      resource,
      params,
      (data) => {
        queryClientRef.current.setQueryData(queryKeyRef.current, data);
      },
      (upserted, removed) => {
        if (!upserted && !removed) return;
        queryClientRef.current.setQueryData(queryKeyRef.current, (old: unknown) => {
          if (!Array.isArray(old)) return old;
          let result = [...old];
          if (removed?.length) {
            const removeSet = new Set(removed);
            result = result.filter(
              (item: unknown) =>
                !(typeof item === "object" && item !== null && "id" in item &&
                  removeSet.has((item as { id: string }).id))
            );
          }
          if (upserted?.length) {
            for (const item of upserted) {
              if (typeof item !== "object" || item === null || !("id" in item)) {
                result.push(item);
                continue;
              }
              const itemId = (item as { id: string }).id;
              const idx = result.findIndex(
                (e: unknown) => typeof e === "object" && e !== null && "id" in e &&
                  (e as { id: string }).id === itemId
              );
              if (idx >= 0) result[idx] = item;
              else result.push(item);
            }
          }
          return result;
        });
      }
    );

    return unsubscribe;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [client, resource, enabled, stableParamsKey]);
}
```

