// POST /mesh/peers -- add and connect to a peer
app.post("/mesh/peers", localhostOnly, async (c) => {
  const body = (await c.req.json()) as PeerInfo;

  if (!body.peerId || !body.deviceToken) {
    return c.json({ error: "peerId and deviceToken required" }, 400);
  }

  addPeer({
    peerId: body.peerId,
    name: body.name || "Unknown Peer",
    deviceToken: body.deviceToken,
    addedAt: Date.now(),
  });
  connectPeer(body.peerId);

  return c.json({ success: true });
});

// DELETE /mesh/peers/:peerId -- remove a peer
app.delete("/mesh/peers/:peerId", localhostOnly, (c) => {
  removePeer(c.req.param("peerId"));
  return c.json({ success: true });
});

// POST /mesh/peers/:peerId/connect -- reconnect to a peer
app.post("/mesh/peers/:peerId/connect", localhostOnly, (c) => {
  connectPeer(c.req.param("peerId"));
  return c.json({ success: true });
});

// POST /mesh/peers/:peerId/disconnect -- disconnect from a peer
app.post("/mesh/peers/:peerId/disconnect", localhostOnly, (c) => {
  disconnectPeer(c.req.param("peerId"));
  return c.json({ success: true });
});

export default app;
```

#### 3. WS Peer Proxy in `app.ts`

The frontend connects to `/ws/peer/:peerId` on its local backend. The backend proxies `q:*` frames to/from the peer via `mesh.service.ts`.

```typescript
// Addition to app.ts — peer WS proxy route
// Mount BEFORE the main /ws route

app.get('/ws/peer/:peerId', upgradeWebSocket((c) => {
  const peerId = c.req.param('peerId');
  const ip = getClientIp(c);

  // Only localhost can use peer proxy
  if (!isLocalhost(ip)) {
    return {
      onOpen(_evt, ws) {
        ws.send(JSON.stringify({ type: 'error', message: 'Localhost only' }));
        ws.close(4003, 'Forbidden');
      },
    };
  }

  return {
    onOpen(_evt, ws) {
      if (!isPeerConnected(peerId)) {
        ws.send(JSON.stringify({ type: 'error', message: 'Peer not connected' }));
        ws.close(4004, 'Peer offline');
        return;
      }

      // Register handler: peer → local WS client
      setPeerMessageHandler(peerId, (payload) => {
        try {
          ws.send(payload);
        } catch {
          // Client disconnected
        }
      });

      ws.send(JSON.stringify({ type: 'connected', peerId }));
    },

    onMessage(evt, _ws) {
      const raw = typeof evt.data === 'string' ? evt.data : String(evt.data);
      // Forward: local WS client → peer
      sendToPeer(peerId, raw);
    },

    onClose() {
      setPeerMessageHandler(peerId, null);
    },
  };
}));
