### File 2: `backend/src/services/peer-mesh.service.ts` -- Core mesh logic

```typescript
// backend/src/services/peer-mesh.service.ts
// Manages peer desktop connections through the cloud relay.
// Desktop A subscribes to Desktop B's resources by forwarding q:* frames
// through the relay tunnel. Responses come back the same way.

import type { QueryResource } from "../../../shared/events";

// ---- Types ----

export interface PeerDesktop {
  serverId: string;
  serverName: string;
  connected: boolean;
  /** Monotonic timestamp of last received frame for health checks */
  lastSeen: number;
}

interface PeerSubscription {
  /** Local subscription ID (what the frontend knows) */
  localSubId: string;
  /** Remote subscription ID (what the peer's query engine knows) */
  remoteSubId: string;
  /** The peer this subscription targets */
  peerId: string;
  resource: QueryResource;
  params?: Record<string, unknown>;
}

// ---- State ----

/** Known peer desktops, keyed by serverId */
const peers = new Map<string, PeerDesktop>();

/** Active subscriptions to peer resources.
 *  Key: localSubId (frontend-facing) → PeerSubscription */
const peerSubs = new Map<string, PeerSubscription>();

/** Reverse map: remoteSubId → localSubId for routing responses */
const remoteToLocal = new Map<string, string>();

/** Callback to send frames through relay tunnel */
let sendToPeer: ((targetServerId: string, payload: string) => void) | null = null;

/** Callback to send frames to a local WS connection (frontend) */
let sendToConnection: ((connectionId: string, frame: Record<string, unknown>) => void) | null = null;

/** Map: localSubId → connectionId (which frontend connection owns this sub) */
const subToConnection = new Map<string, string>();

let subCounter = 0;

// ---- Init ----

export function initPeerMesh(
  relaySend: (targetServerId: string, payload: string) => void,
  localSend: (connectionId: string, frame: Record<string, unknown>) => void,
): void {
  sendToPeer = relaySend;
  sendToConnection = localSend;
}

// ---- Peer Lifecycle ----

export function addPeer(serverId: string, serverName: string): void {
  peers.set(serverId, {
    serverId,
    serverName,
    connected: true,
    lastSeen: Date.now(),
  });
}

export function removePeer(serverId: string): void {
  peers.delete(serverId);
  // Clean up all subscriptions to this peer
  for (const [localId, sub] of peerSubs) {
    if (sub.peerId === serverId) {
      remoteToLocal.delete(sub.remoteSubId);
      subToConnection.delete(localId);
      peerSubs.delete(localId);
    }
  }
}

export function getPeers(): PeerDesktop[] {
  return [...peers.values()];
}

// ---- Subscription Forwarding ----

/**
 * Subscribe to a remote peer's resource. Forwards q:subscribe through
 * the relay and tracks the mapping so responses route back correctly.
 */
export function subscribeToPeer(
  connectionId: string,
  localSubId: string,
  peerId: string,
  resource: QueryResource,
  params?: Record<string, unknown>,
): void {
  if (!sendToPeer) return;

  const peer = peers.get(peerId);
  if (!peer?.connected) {
    sendToConnection?.(connectionId, {
      type: "q:error",
      id: localSubId,
      code: "PEER_OFFLINE",
      message: `Peer ${peerId} is not connected`,
    });
    return;
  }

  const remoteSubId = `peer_sub_${++subCounter}`;

  peerSubs.set(localSubId, {
    localSubId,
    remoteSubId,
    peerId,
    resource,
    params,
  });
  remoteToLocal.set(remoteSubId, localSubId);
  subToConnection.set(localSubId, connectionId);

  // Forward q:subscribe to the peer through relay
  sendToPeer(peerId, JSON.stringify({
    type: "q:subscribe",
    id: remoteSubId,
    resource,
    ...(params ? { params } : {}),
  }));
}

/**
 * Unsubscribe from a remote peer's resource.
 */
export function unsubscribeFromPeer(localSubId: string): void {
  const sub = peerSubs.get(localSubId);
  if (!sub) return;

  // Send unsubscribe to peer
  sendToPeer?.(sub.peerId, JSON.stringify({
    type: "q:unsubscribe",
    id: sub.remoteSubId,
  }));

  remoteToLocal.delete(sub.remoteSubId);
  subToConnection.delete(localSubId);
  peerSubs.delete(localSubId);
}

/**
 * Forward a one-shot q:request to a peer.
 */
export function requestFromPeer(
  connectionId: string,
  localReqId: string,
  peerId: string,
  resource: QueryResource,
  params?: Record<string, unknown>,
): void {
  if (!sendToPeer) return;

  const peer = peers.get(peerId);
  if (!peer?.connected) {
    sendToConnection?.(connectionId, {
      type: "q:error",
      id: localReqId,
      code: "PEER_OFFLINE",
      message: `Peer ${peerId} is not connected`,
    });
    return;
  }

  // Use localReqId directly as remoteSubId for requests (1:1 mapping)
  const remoteReqId = `peer_req_${++subCounter}`;
  remoteToLocal.set(remoteReqId, localReqId);
  subToConnection.set(localReqId, connectionId);

  sendToPeer(peerId, JSON.stringify({
    type: "q:request",
    id: remoteReqId,
    resource,
    ...(params ? { params } : {}),
  }));
}

/**
 * Forward a mutation to a peer.
 */
export function mutateOnPeer(
  connectionId: string,
  localMutateId: string,
  peerId: string,
  action: string,
  params: Record<string, unknown>,
): void {
  if (!sendToPeer) return;

  const peer = peers.get(peerId);
  if (!peer?.connected) {
    sendToConnection?.(connectionId, {
      type: "q:mutate_result",
      id: localMutateId,
      success: false,
      error: `Peer ${peerId} is not connected`,
    });
    return;
  }

  const remoteId = `peer_mut_${++subCounter}`;
  remoteToLocal.set(remoteId, localMutateId);
  subToConnection.set(localMutateId, connectionId);

  sendToPeer(peerId, JSON.stringify({
    type: "q:mutate",
    id: remoteId,
    action,
    params,
  }));
}

/**
 * Handle a response frame from a peer (routed through relay).
 * Remaps the subscription/request ID and forwards to the local frontend connection.
 */
export function handlePeerResponse(sourceServerId: string, payload: string): void {
  let msg: Record<string, unknown>;
  try {
    msg = JSON.parse(payload);
  } catch {
    return;
  }

  const type = msg.type as string;
  if (!type?.startsWith("q:")) return;

  // Update peer lastSeen
  const peer = peers.get(sourceServerId);
  if (peer) peer.lastSeen = Date.now();

  const remoteId = msg.id as string;
  if (!remoteId) {
    // q:invalidate has no id — broadcast to all connections subscribed to this peer
    if (type === "q:invalidate") {
      // Forward invalidation to all connections that have subs to this peer
      const connectionIds = new Set<string>();
      for (const [localId, sub] of peerSubs) {
        if (sub.peerId === sourceServerId) {
          const connId = subToConnection.get(localId);
          if (connId) connectionIds.add(connId);
        }
      }
      for (const connId of connectionIds) {
        sendToConnection?.(connId, msg);
      }
    }
    return;
  }

  const localId = remoteToLocal.get(remoteId);
  if (!localId) return;

  const connectionId = subToConnection.get(localId);
  if (!connectionId) return;

  // Remap the ID from remote to local
  msg.id = localId;

  // For one-shot responses (q:response, q:error on requests), clean up mappings
  if (type === "q:response" || (type === "q:error" && !peerSubs.has(localId))) {
    remoteToLocal.delete(remoteId);
    subToConnection.delete(localId);
  }

  // For mutation results, clean up
  if (type === "q:mutate_result") {
    remoteToLocal.delete(remoteId);
    subToConnection.delete(localId);
  }

  sendToConnection?.(connectionId, msg);
}

/**
 * Clean up all peer subscriptions for a disconnected frontend connection.
 */
export function removeConnectionSubs(connectionId: string): void {
  for (const [localId, sub] of peerSubs) {
    if (subToConnection.get(localId) === connectionId) {
      sendToPeer?.(sub.peerId, JSON.stringify({
        type: "q:unsubscribe",
        id: sub.remoteSubId,
      }));
      remoteToLocal.delete(sub.remoteSubId);
      subToConnection.delete(localId);
      peerSubs.delete(localId);
    }
  }
}

// ---- Test helpers ----

export function _clearAll(): void {
  peers.clear();
  peerSubs.clear();
  remoteToLocal.clear();
  subToConnection.clear();
  sendToPeer = null;
  sendToConnection = null;
  subCounter = 0;
}
