// Add to imports:
import {
  subscribeToPeer,
  unsubscribeFromPeer,
  requestFromPeer,
  mutateOnPeer,
  removeConnectionSubs,
} from "./peer-mesh.service";

// Modify handleFrame to intercept peer-prefixed resources:
export function handleFrame(connectionId: string, msg: QueryParams): void {
  const type = typeof msg.type === "string" ? msg.type : "unknown";

  // Check if this is a peer-targeted frame (resource starts with "peer:")
  const resource = typeof msg.resource === "string" ? msg.resource : "";
  const peerMatch = resource.match(/^peer:([^:]+):(.+)$/);

  if (peerMatch && (type === "q:subscribe" || type === "q:request")) {
    const [, peerId, actualResource] = peerMatch;
    const id = typeof msg.id === "string" ? msg.id : "unknown";
    const params = getParams(msg.params);

    if (type === "q:subscribe") {
      subscribeToPeer(connectionId, id, peerId, actualResource as QueryResource, params);
    } else {
      requestFromPeer(connectionId, id, peerId, actualResource as QueryResource, params);
    }
    return;
  }

  // Check for peer-targeted mutations (action starts with "peer:")
  const action = typeof msg.action === "string" ? msg.action : "";
  const peerMutMatch = action.match(/^peer:([^:]+):(.+)$/);

  if (peerMutMatch && type === "q:mutate") {
    const [, peerId, actualAction] = peerMutMatch;
    const id = typeof msg.id === "string" ? msg.id : "unknown";
    const params = getParams(msg.params);
    mutateOnPeer(connectionId, id, peerId, actualAction, params);
    return;
  }

  // Existing local handling (unchanged)
  try {
    match(type)
      .with("q:request", () => handleRequest(connectionId, parseResourceFrame(msg)))
      // ... rest unchanged
  }
}

// Modify removeSubs to also clean up peer subscriptions:
export function removeSubs(connectionId: string): void {
  // Existing local cleanup
  const connSubs = subs.get(connectionId);
  if (connSubs) {
    for (const [subId, sub] of connSubs) {
      if (sub.resource === "messages") {
        messageCursors.delete(`${connectionId}:${subId}`);
      }
    }
    subs.delete(connectionId);
  }

  // NEW: Clean up peer subscriptions too
  removeConnectionSubs(connectionId);
