```typescript
// src/shared/hooks/usePeerSubscription.ts
// Subscribe to a remote peer's resources through the query protocol.
// Uses the same WS subscription mechanism but with peer-prefixed resources.

import { useEffect, useMemo, useRef } from "react";
import { useQueryClient, type QueryKey } from "@tanstack/react-query";
import { subscribe, isConnected } from "@/platform/ws";
import type { QueryResource } from "@shared/types/query-protocol";

interface UsePeerSubscriptionOptions {
  queryKey: QueryKey;
  peerId: string;
  params?: Record<string, unknown>;
  enabled?: boolean;
}

/**
 * Subscribe to a peer desktop's resource via the relay mesh.
 * Works exactly like useQuerySubscription but targets a remote peer.
 *
 * The local query engine intercepts "peer:{peerId}:{resource}" and
 * forwards the subscription through the relay tunnel.
 */
export function usePeerSubscription(
  resource: QueryResource,
  options: UsePeerSubscriptionOptions,
): void {
  const { queryKey, peerId, params, enabled = true } = options;
  const queryClient = useQueryClient();

  const stableParamsKey = useMemo(
    () => (params ? JSON.stringify(params) : ""),
    [params],
  );

  const queryClientRef = useRef(queryClient);
  queryClientRef.current = queryClient;

  const queryKeyRef = useRef(queryKey);
  queryKeyRef.current = queryKey;

  useEffect(() => {
    if (!enabled || !isConnected() || !peerId) return;

    // The magic: prefix resource with peer ID. The local query engine
    // intercepts this and forwards through the relay to the peer.
    const peerResource = `peer:${peerId}:${resource}` as QueryResource;

    const unsubscribe = subscribe(
      peerResource,
      params,
      (data) => {
        queryClientRef.current.setQueryData(queryKeyRef.current, data);
      },
      (upserted, removed) => {
        if (!upserted && !removed) return;

        queryClientRef.current.setQueryData(queryKeyRef.current, (old: unknown) => {
          if (!Array.isArray(old)) return old;

          let result = [...old];

          if (removed && removed.length > 0) {
            const removeSet = new Set(removed);
            result = result.filter(
              (item: unknown) =>
                !(
                  typeof item === "object" &&
                  item !== null &&
                  "id" in item &&
                  removeSet.has((item as { id: string }).id)
                ),
            );
          }

          if (upserted && upserted.length > 0) {
            for (const item of upserted) {
              if (typeof item !== "object" || item === null || !("id" in item)) {
                result.push(item);
                continue;
              }
              const itemId = (item as { id: string }).id;
              const idx = result.findIndex(
                (existing: unknown) =>
                  typeof existing === "object" &&
                  existing !== null &&
                  "id" in existing &&
                  (existing as { id: string }).id === itemId,
              );
              if (idx >= 0) {
                result[idx] = item;
              } else {
                result.push(item);
              }
            }
          }

          return result;
        });
      },
    );

    return unsubscribe;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [resource, peerId, enabled, stableParamsKey]);
}
